//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagevalidationimport("fmt""regexp""testing""github.com/hashicorp/go-cty/cty""github.com/hashicorp/terraform-plugin-sdk/v2/diag""github.com/hashicorp/terraform-plugin-sdk/v2/helper/schema")typetestCasestruct{valinterface{}fhema.SchemaValidateexpectedErr*regexp.Regexp}runTestCases(t*testing.T,cases[]testCase){t.Helper()fori,tc:=rangecases{t.Run(fmt.Sprintf("TestCase_%d",i),(t*testing.T){_,errs:=tc.f(tc.val,"test_property")iflen(errs)==0&&tc.expectedErr==nil{return}iflen(errs)!=0&&tc.expectedErr==nil{t.Fatalf("expectedtestcase%dtoproducenoerrors,got%v",i,errs)}if!matchAnyError(errs,tc.expectedErr){t.Fatalf("expectedtestcase%dtoproduceerrormatching\"%s\",got%v",i,tc.expectedErr,errs)}})}}typediagTestCasestruct{valmaValidateDiagexpectedDiagSummary*regexp.Regexp}runDiagTestCases(t*testing.T,cases[]diagTestCase){t.Helper()fori,tc:=rangecases{t.Run(fmt.Sprintf("TestCase_%d",i),(t*testing.T){diags:=tc.f(tc.val,cty.GetAttrPath("test_property"))iflen(diags)==0&&tc.expectedDiagSummary==nil{return}iflen(diags)!=0&&tc.expectedDiagSummary==nil{t.Fatalf("expectedtestcase%dtoproducenodiagnostics,got%v",i,diags)}if!matchAnyDiagSummary(diags,tc.expectedDiagSummary){t.Fatalf("expectedtestcase%dtoproducediagnosticsummarymatching\"%s\",got%v",i,tc.expectedDiagSummary,diags)}})}}matchAnyError(errs[]error,r*regexp.Regexp)bool{//errmustmatchoneprovidedfor_,err:=rangeerrs{r.MatchString(err.Error()){returntrue}}returnfalse}matchAnyDiagSummary(dsdiag.Diagnostics,r*regexp.Regexp)bool{for_,d:=rangeds{ifr.MatchString(d.Summary){returntrue}}returnfalse}